CREATE TRIGGER dbo.trg_Audit ON dbo.Accounts AFTER UPDATE AS
BEGIN
    DECLARE @id INT, @bal DECIMAL(18,2);
    SELECT @id = AccountId, @bal = Balance FROM inserted;
    INSERT INTO dbo.AccountAudit (AccountId, NewBalance, ChangedAtUtc)
    VALUES (@id, @bal, SYSUTCDATETIME());
END;

